import tempfile, os
doc = Rhino.RhinoDoc.ActiveDoc
selected = [obj.Id for obj in doc.Objects.GetSelectedObjects(False, False)]
if len(selected) == 0:
    return {"ok": False, "error": "no objects selected"}
target = os.path.join(tempfile.gettempdir(), "aware-drill.stl")
cmd = '_-Export "%s" _Enter _Enter' % target
issued = Rhino.RhinoApp.RunScript(cmd, False)
return {"ok": issued, "path": target, "selected_count": len(selected)}
